<?php require __DIR__.'/_helpers.php'; $title='Réceptions'; include __DIR__.'/../layouts/header.php'; $rows=receptions_all();
$q=trim($_GET['q']??''); $status=$_GET['status']??''; $from=$_GET['from']??''; $to=$_GET['to']??'';
if($q!=='') $rows=array_values(array_filter($rows,fn($r)=>stripos(($r['ref']??'').' '.($r['tier_name']??'').' '.($r['warehouse_name']??''),$q)!==false));
if($status!=='') $rows=array_values(array_filter($rows,fn($r)=>($r['status']??'')===$status));
if($from!=='') $rows=array_values(array_filter($rows,fn($r)=>($r['date']??'')>=$from));
if($to!=='') $rows=array_values(array_filter($rows,fn($r)=>($r['date']??'')<=$to));
[$rows,$rowsTotal,$rowsPage,$rowsPages]=ge_list_paginate_current($rows);
?>
<div class="clean-list-page dol-list-page">
