  <tr><th>▾ Réf.</th><th>Fournisseur</th><th>Date réception</th><th>Entrepôt</th><th>État</th><th><i class="fa-solid fa-list"></i> <input type="checkbox" id="checkAllRec"></th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><i class="fa-solid fa-cart-flatbed text-blue"></i> <a class="ref" href="index.php?page=reception_show&id=<?=(int)$r['id']?>"><?=e($r['ref']??'')?></a></td><td><?=e($r['tier_name']??'')?></td><td><?=e($r['date']??'')?></td><td><?=e($r['warehouse_name']??'')?></td><td><span class="badge <?=e(reception_status_badge($r['status']??''))?>"><?=e($r['status']??'')?></span></td><td><input form="bulkRec" class="rowCheckRec" type="checkbox" name="ids[]" value="<?=(int)$r['id']?>"></td></tr><?php endforeach; if(!$rows): ?><tr><td colspan="6" class="empty-row">Aucune réception</td></tr><?php endif; ?></tbody></table></div><?=ge_list_pager($rowsTotal,$rowsPage,$rowsPages,'p',['page'=>'receptions'])?></div>
